import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common'; // 🚀 Indispensable pour injecter NgClass et les Pipes de dates

@Component({
  selector: 'app-applications-list',
  standalone: true,
  imports: [CommonModule], // ngClass est hébergé ici
  templateUrl: './applications-list.component.html',
  styleUrls: ['./applications-list.component.css']
})
export class ApplicationsListComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  historyList: any[] = [];
  isLoading: boolean = true;

  ngOnInit() {
    this.fetchCandidateHistory();
  }

  fetchCandidateHistory() {
    const targetUrl = 'http://localhost:3000/api/candidate/history';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(async res => {
      if (!res.ok) throw new Error("Impossible de lire votre historique.");
      return res.json();
    })
    .then(data => {
      // Stocke le tableau history retourné par l'API
      this.historyList = data.history || [];
      this.isLoading = false;
      this.cdr.detectChanges(); // Met à jour l'interface Tailwind instantanément
    })
    .catch(err => {
      console.error("Erreur historique candidat :", err);
      this.isLoading = false;
      this.cdr.detectChanges();
    });
  }
}
<div class="manage-container">

  <!-- En-tête de la page -->
  <div class="card-header-flex">
    <div class="card-header-left">
      <h3><i class="bi bi-file-earmark-check-fill"></i> Suivi de mes candidatures</h3>
      <p>Consultez l'état d'avancement et les réponses des recruteurs pour vos postes postulés.</p>
    </div>
  </div>

  <!-- 📋 CARTE DU TABLEAU DE SUIVI -->
  <div class="manage-card">
    <div class="table-wrapper">
      <table class="jobs-table">
        <thead>
          <tr>
            <th style="padding-left: 20px;">Poste / Entreprise</th>
            <th>Date d'envoi</th>
            <th style="text-align: center; padding-right: 20px;">Statut</th>
          </tr>
        </thead>
        <tbody>
          
          <!-- ⏳ État de chargement asynchrone -->
          @if (isLoading) {
            <tr>
              <td colspan="3" style="text-align: center; padding: 25px; color: #64748b; font-weight: 500;">
                <i class="bi bi-arrow-clockwise" style="display: inline-block; animation: spin 1s linear infinite; margin-right: 8px;"></i>
                Chargement de votre historique de postulation...
              </td>
            </tr>
          }

          <!-- 🚫 Cas où le catalogue est vide -->
          @if (!isLoading && historyList.length === 0) {
            <tr>
              <td colspan="3" style="text-align: center; padding: 35px; color: #64748b;">
                <i class="bi bi-send-x-fill" style="font-size: 26px; display: block; margin-bottom: 6px; color: #cbd5e1;"></i>
                Vous n'avez pas encore envoyé de candidatures.
              </td>
            </tr>
          }

          <!-- 🚀 RENDU DYNAMIQUE DES LIGNES MYSQL -->
          @for (app of historyList; track app.job_id) {
            <tr class="table-row-hover">
              <!-- Colonne 1 : Poste et Entreprise regroupés -->
              <td style="padding-left: 20px;">
                <span class="job-main-title">{{ app.job_title }}</span>
                <span class="company-sub-badge"><i class="bi bi-building"></i> {{ app.company_name }}</span>
              </td>
              
              <!-- Colonne 2 : Date d'envoi -->
              <td class="date-text-cell">
                <i class="bi bi-calendar3"></i> {{ app.applied_at | date:'dd/MM/yyyy' }}
              </td>
              
              <!-- Colonne 3 : Badge de statut coloré -->
              <td style="text-align: center; padding-right: 20px;">
                <span class="status-badge" [ngClass]="{
                  'bg-amber': app.status === 'Nouveau' || app.status === 'en_attente',
                  'bg-blue': app.status === 'Entretien',
                  'bg-emerald': app.status === 'retenu' || app.status === 'Acceptée',
                  'bg-red': app.status === 'refuse' || app.status === 'Refusée'
                }">
                  <span class="dot-status"></span>
                  {{ app.status === 'Nouveau' || app.status === 'en_attente' ? 'En attente' : app.status === 'retenu' || app.status === 'Acceptée' ? 'Retenu' : app.status === 'refuse' || app.status === 'Refusée' ? 'Refusé' : app.status }}
                </span>
              </td>
            </tr>
          }
          
        </tbody>
      </table>
    </div>
  </div>

</div>
